class CircularQueue:
    def __init__(self,kap):
        self.dizi=[None]*kap; self.kap=kap
        self.on=0; self.arka=0; self.boyut=0
    def enqueue(self,val):
        if self.boyut==self.kap: raise OverflowError()
        self.dizi[self.arka]=val
        self.arka=(self.arka+1)%self.kap; self.boyut+=1
    def dequeue(self):
        if self.boyut==0: raise IndexError()
        val=self.dizi[self.on]
        self.on=(self.on+1)%self.kap; self.boyut-=1
        return val
