class LinearProbing:
    def __init__(self,b=10):
        self.b=b; self.keys=[None]*b; self.values=[None]*b
    def ekle(self,k,v):
        i=hash(k)%self.b
        while self.keys[i] is not None:
            if self.keys[i]==k: self.values[i]=v; return
            i=(i+1)%self.b
        self.keys[i]=k; self.values[i]=v
