import hashlib
class ConsistentHash:
    def __init__(self,sanal=150):
        self.sanal=sanal; self.halka={}; self.sunucular=set()
    def _hash(self,k):
        return int(hashlib.md5(str(k).encode()).hexdigest()[:8],16)
    def sunucu_ekle(self,s):
        for i in range(self.sanal):
            self.halka[self._hash(f'{s}:{i}')]=s
        self.sunucular.add(s)
    def getir(self,k):
        p=self._hash(k)
        for h in sorted(self.halka.keys()):
            if p<=h: return self.halka[h]
        return self.halka[sorted(self.halka.keys())[0]]
