class SegmentTree:
    def __init__(self,dizi):
        self.n=len(dizi); self.tree=[0]*(4*self.n)
        self._build(dizi,0,0,self.n-1)
    def _build(self,dizi,node,bas,son):
        if bas==son: self.tree[node]=dizi[bas]; return
        orta=(bas+son)//2
        self._build(dizi,2*node+1,bas,orta)
        self._build(dizi,2*node+2,orta+1,son)
        self.tree[node]=self.tree[2*node+1]+self.tree[2*node+2]
    def sorgula(self,l,r):
        return self._sorgula(0,0,self.n-1,l,r)
    def _sorgula(self,node,bas,son,l,r):
        if l<=bas and son<=r: return self.tree[node]
        if son<l or bas>r: return 0
        orta=(bas+son)//2
        return self._sorgula(2*node+1,bas,orta,l,r)+self._sorgula(2*node+2,orta+1,son,l,r)

