def bucket_sort(arr):
    if not arr: return arr
    maks,mn=max(arr),min(arr)
    aralik=(maks-mn)/len(arr)
    buckets=[[] for _ in range(len(arr))]
    for s in arr:
        if s==maks: buckets[-1].append(s)
        else: buckets[int((s-mn)/aralik)].append(s)
    sonuc=[]
