def cocktail_sort(arr):
    n=len(arr); bas=0; son=n-1; swapped=True
    while swapped:
        swapped=False
        for i in range(bas,son):
            if arr[i]>arr[i+1]:
                arr[i],arr[i+1]=arr[i+1],arr[i]; swapped=True
        if not swapped: break
        son-=1
        for i in range(son-1,bas-1,-1):
            if arr[i]>arr[i+1]:
                arr[i],arr[i+1]=arr[i+1],arr[i]; swapped=True
        bas+=1
    return arr

