def pancake_sort(arr):
    def flip(arr,k):
        arr[:k+1]=reversed(arr[:k+1])
    n=len(arr)
    for boyut in range(n,1,-1):
        mx=0
        for i in range(boyut):
            if arr[i]>arr[mx]: mx=i
        if mx!=boyut-1:
            flip(arr,mx); flip(arr,boyut-1)
