class ShardManager:
    def __init__(self):
        self.sunsayisi=4
        self.baglantilar={}
    def _shard_id(self,kullanici_id):
        return hash(kullanici_id)%self.sunsayisi
    def kullanici_kaydet(self,kullanici):
