# Error budget
class ErrorBudget:
    def __init__(self,slo):
        self.slo=slo
        self.toplam_sure=365*24*60*60
        self.izinli_hata=self.toplam_sure*(100-slo)/100
        self.kullanilan_hata=0
    def hata_ekle(self,sure):
        self.kullanilan_hata+=sure
        return self.kalan()
    def kalan(self):
        return self.izinli_hata-self.kullanilan_hata

