```python
def n_queens(n):
    def guvenli_mi(board,satir,sutun):
        for i in range(satir):
            if board[i]==sutun or abs(board[i]-sutun)==abs(i-satir):
                return False
        return True

    def coz(board,satir):
        if satir==n:
            cozumler.append(board[:])
            return
        for sutun in range(n):
            if guvenli_mi(board,satir,sutun):
                board[satir]=sutun
                coz(board,satir+1)
                board[satir]=-1

    cozumler=[]
    coz([-1]*n,0)
    return cozumler

