```python
def avl_ekle(root,val):
    if not root: return AVLNode(val)
    if val<root.val: root.left=avl_ekle(root.left,val)
    else: root.right=avl_ekle(root.right,val)

    root.yuk=1+max(yuk(root.left),yuk(root.right))
    dg=denge(root)

    if dg>1 and val<root.left.val: return saga_dondur(root)
    if dg<-1 and val>root.right.val: return sola_dondur(root)
    if dg>1 and val>root.left.val:
        root.left=sola_dondur(root.left); return saga_dondur(root)
    if dg<-1 and val<root.right.val:
        root.right=saga_dondur(root.right); return sola_dondur(root)
    return root
```

