```python
def autocorrect(trie,kelime):
    oneriler=[]
    def dfs(node,prefix):
        if node.bitis:
            oneriler.append(prefix)
        for c,child in sorted(node.cocuklar.items()):
            if len(oneriler)<5:
                dfs(child,prefix+c)
    # En yakin prefix bul
    node=trie.kok
    prefix=''
    for c in kelime:
        if c not in node.cocuklar: break
        node=node.cocuklar[c]; prefix+=c
    dfs(node,prefix)
    return oneriler
```

